# Definition for a binary tree node.
# class TreeNode:
#     def __init__(self, val=0, left=None, right=None):
#         self.val = val
#         self.left = left
#         self.right = right
class Solution:
    def getMinimumDifference(self, root: Optional[TreeNode]) -> int:
        prev = 0

        while root:
            if root.left:
                prev = root.val
                root = root.left
            elif root.right:
                prev = root.val
                root = root.right
            else:
                return prev - root.val

        return 0

# Definition for a binary tree node.
# class TreeNode:
#     def __init__(self, val=0, left=None, right=None):
#         self.val = val
#         self.left = left
#         self.right = right
class Solution:
    def getMinimumDifference(self, root: Optional[TreeNode]) -> int:
        prev = 0

        while root:
            if root.left:
                prev = root.val
                root = root.left
            elif root.right:
                prev = root.val
                root = root.right
            else:
                return abs(prev - root.val)

        return 0
